// src/pages/Budget.jsx
// Análisis inteligente de gastos:
// - En qué gastas más
// - Comparativa entre categorías
// - Recomendaciones personalizadas basadas en los datos reales

import { useTransactions } from '../hooks/useTransactions'
import { formatCurrency }  from '../utils/formatCurrency'
import styles from './Budget.module.css'

const CATEGORY_EMOJI = {
  alimentación: '🛒', transporte: '🚗', vivienda: '🏠', salud: '💊',
  entretenimiento: '🎬', educación: '📚', ropa: '👕', otros: '📦',
}

// ── Motor de recomendaciones ────────────────────────────────────────
// Analiza los datos reales del usuario y genera consejos concretos
const generateRecommendations = (summary, transactions) => {
  const recs = []
  if (!summary || !transactions.length) return recs

  const { totalIncome, totalExpense, balance, byCategory } = summary

  // 1. Balance negativo
  if (balance < 0) {
    recs.push({
      type: 'danger',
      icon: '🚨',
      title: 'Estás gastando más de lo que ingresas',
      desc: `Tu déficit es de ${formatCurrency(Math.abs(balance))}. Revisa los gastos más altos y busca cuáles puedes reducir esta semana.`,
    })
  }

  // 2. Balance positivo y saludable
  if (balance > 0 && totalIncome > 0) {
    const savingRate = Math.round((balance / totalIncome) * 100)
    if (savingRate >= 20) {
      recs.push({
        type: 'success',
        icon: '🏆',
        title: `Excelente: estás ahorrando el ${savingRate}% de tus ingresos`,
        desc: 'Considera invertir parte de ese ahorro en un CDT o fondo de inversión para hacer crecer tu dinero.',
      })
    } else {
      recs.push({
        type: 'warning',
        icon: '💡',
        title: `Ahorras el ${savingRate}% de tus ingresos`,
        desc: 'Lo ideal es ahorrar al menos el 20%. Intenta reducir gastos en entretenimiento o ropa para llegar a esa meta.',
      })
    }
  }

  // 3. Categoría dominante
  if (byCategory && Object.keys(byCategory).length > 0) {
    const [topCat, topAmt] = Object.entries(byCategory).sort((a, b) => b[1] - a[1])[0]
    const pct = totalExpense ? Math.round((topAmt / totalExpense) * 100) : 0
    if (pct > 40) {
      recs.push({
        type: 'warning',
        icon: CATEGORY_EMOJI[topCat] || '📦',
        title: `${pct}% de tus gastos van a "${topCat}"`,
        desc: `Estás concentrando demasiado en una sola categoría. Evalúa si puedes optimizar en ${topCat} para liberar presupuesto.`,
      })
    }
  }

  // 4. Sin ingresos registrados
  if (totalIncome === 0 && totalExpense > 0) {
    recs.push({
      type: 'warning',
      icon: '📥',
      title: 'No tienes ingresos registrados',
      desc: 'Registra tus ingresos para ver tu balance real y obtener análisis más precisos.',
    })
  }

  // 5. Entretenimiento alto
  const entAmt = byCategory?.entretenimiento || 0
  if (totalExpense > 0 && entAmt / totalExpense > 0.25) {
    recs.push({
      type: 'warning',
      icon: '🎬',
      title: 'El entretenimiento consume más del 25% de tus gastos',
      desc: 'Busca alternativas gratuitas o de menor costo: plataformas compartidas, actividades al aire libre, etc.',
    })
  }

  // 6. Todo bien
  if (recs.length === 0) {
    recs.push({
      type: 'success',
      icon: '✅',
      title: 'Tus finanzas se ven saludables',
      desc: 'Sigue registrando tus movimientos para mantener el control. Considera establecer metas de ahorro mensuales.',
    })
  }

  return recs
}

export default function Budget() {
  const { transactions, summary, loading, error } = useTransactions()

  if (loading) return <div className={styles.center}>Analizando tus finanzas...</div>
  if (error)   return <div className="msg msg--error">{error}</div>

  const { totalIncome = 0, totalExpense = 0, balance = 0, byCategory = {} } = summary || {}
  const recommendations = generateRecommendations(summary, transactions)

  // Ordenar categorías de mayor a menor gasto
  const sortedCategories = Object.entries(byCategory).sort((a, b) => b[1] - a[1])
  const topCategory      = sortedCategories[0]

  return (
    <div className={styles.page}>
      <h1 className={styles.title}>Análisis de Gastos</h1>

      {/* ── En qué gastas más ─────────────────────── */}
      {topCategory && (
        <div className={`card ${styles.topCard}`}>
          <span className={styles.topEmoji}>{CATEGORY_EMOJI[topCategory[0]] || '📦'}</span>
          <div>
            <p className={styles.topLabel}>En qué gastas más</p>
            <p className={styles.topCat}>{topCategory[0].charAt(0).toUpperCase() + topCategory[0].slice(1)}</p>
            <p className={styles.topAmt}>{formatCurrency(topCategory[1])}
              <span className={styles.topPct}>
                {totalExpense ? ` · ${Math.round((topCategory[1] / totalExpense) * 100)}% de tus gastos` : ''}
              </span>
            </p>
          </div>
        </div>
      )}

      <div className="grid-2" style={{ marginBottom: 24 }}>
        {/* ── Desglose por categoría ─────────────────── */}
        <div className="card">
          <p className="card-title">Desglose por categoría</p>
          {sortedCategories.length === 0 ? (
            <p style={{ color: 'var(--text-2)', fontSize: '0.9rem' }}>Sin gastos registrados.</p>
          ) : (
            <ul className={styles.catList}>
              {sortedCategories.map(([cat, amt]) => {
                const pct = totalExpense ? Math.round((amt / totalExpense) * 100) : 0
                return (
                  <li key={cat} className={styles.catRow}>
                    <div className={styles.catHead}>
                      <span>{CATEGORY_EMOJI[cat] || '📦'} {cat.charAt(0).toUpperCase() + cat.slice(1)}</span>
                      <span>{formatCurrency(amt)} <span className={styles.pct}>({pct}%)</span></span>
                    </div>
                    <div className={styles.barBg}>
                      <div className={styles.barFill} style={{ width: `${pct}%` }} />
                    </div>
                  </li>
                )
              })}
            </ul>
          )}
        </div>

        {/* ── Resumen financiero ─────────────────────── */}
        <div className="card">
          <p className="card-title">Resumen financiero</p>
          <ul className={styles.summaryList}>
            <li className={styles.summaryRow}>
              <span>💚 Total ingresos</span>
              <span className={styles.pos}>{formatCurrency(totalIncome)}</span>
            </li>
            <li className={styles.summaryRow}>
              <span>🔴 Total gastos</span>
              <span className={styles.neg}>{formatCurrency(totalExpense)}</span>
            </li>
            <li className={`${styles.summaryRow} ${styles.balanceRow}`}>
              <span>⚖️ Balance</span>
              <span className={balance >= 0 ? styles.pos : styles.neg}>{formatCurrency(balance)}</span>
            </li>
            {totalIncome > 0 && (
              <li className={styles.summaryRow}>
                <span>💾 Tasa de ahorro</span>
                <span>{Math.round((balance / totalIncome) * 100)}%</span>
              </li>
            )}
            <li className={styles.summaryRow}>
              <span>📋 Transacciones</span>
              <span>{transactions.length}</span>
            </li>
          </ul>
        </div>
      </div>

      {/* ── Recomendaciones ───────────────────────────── */}
      <div className="card">
        <p className="card-title">💡 Recomendaciones personalizadas</p>
        <div className={styles.recList}>
          {recommendations.map((r, i) => (
            <div key={i} className={`${styles.rec} ${styles[r.type]}`}>
              <span className={styles.recIcon}>{r.icon}</span>
              <div>
                <p className={styles.recTitle}>{r.title}</p>
                <p className={styles.recDesc}>{r.desc}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}
